import{_ as a,o as e,c as s,aw as n}from"./chunks/framework.Dq2onT5h.js";const o=JSON.parse('{"title":"ADR 018: Store RPC Layer Implementation using Connect-RPC","description":"","frontmatter":{"head":[["meta",{"name":"og:title","content":"ADR 018: Store RPC Layer Implementation using Connect-RPC | Evolve"},{"name":"og:description","content":false}]]},"headers":[],"relativePath":"adr/adr-018-rpc.md","filePath":"adr/adr-018-rpc.md","lastUpdated":1754470767000}');const l=a({name:"adr/adr-018-rpc.md"},[["render",function(a,o,l,t,r,p){return e(),s("div",null,[...o[0]||(o[0]=[n('<h1 id="adr-018-store-rpc-layer-implementation-using-connect-rpc" tabindex="-1">ADR 018: Store RPC Layer Implementation using Connect-RPC <a class="header-anchor" href="#adr-018-store-rpc-layer-implementation-using-connect-rpc" aria-label="Permalink to &quot;ADR 018: Store RPC Layer Implementation using Connect-RPC&quot;">​</a></h1><h2 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h2><ul><li>2024-03-25: Initial proposal</li><li>2025-04-23: Renumbered from ADR-017 to ADR-018 to maintain chronological order.</li></ul><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>The Evolve store package provides a critical interface for storing and retrieving blocks, commits, and state data. Currently, this functionality is only available locally through direct Go package imports. To enable remote access to this data and improve the system&#39;s scalability and interoperability, we need to implement a remote procedure call (RPC) layer.</p><p>Connect-Go has been chosen as the RPC framework due to its modern features, excellent developer experience, and compatibility with both gRPC and HTTP/1.1 protocols.</p><h2 id="alternative-approaches" tabindex="-1">Alternative Approaches <a class="header-anchor" href="#alternative-approaches" aria-label="Permalink to &quot;Alternative Approaches&quot;">​</a></h2><h3 id="pure-grpc" tabindex="-1">Pure gRPC <a class="header-anchor" href="#pure-grpc" aria-label="Permalink to &quot;Pure gRPC&quot;">​</a></h3><ul><li>Pros: Mature ecosystem, wide adoption</li><li>Cons: More complex setup, less flexible protocol support, requires more boilerplate</li></ul><h3 id="rest-api" tabindex="-1">REST API <a class="header-anchor" href="#rest-api" aria-label="Permalink to &quot;REST API&quot;">​</a></h3><ul><li>Pros: Familiar, widely supported</li><li>Cons: No built-in streaming, manual schema definition required</li></ul><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p>Implement a Connect-Go service layer that exposes the Store interface functionality through a well-defined protocol buffer schema and Connect-Go service definitions.</p><p><a href="https://connectrpc.com/docs/go/getting-started/" target="_blank" rel="noreferrer">Connect-Go</a> is a lightweight gRPC library that provides REST out of the box, allowing users to switch between implementations.</p><h2 id="detailed-design" tabindex="-1">Detailed Design <a class="header-anchor" href="#detailed-design" aria-label="Permalink to &quot;Detailed Design&quot;">​</a></h2><h3 id="protocol-buffer-definitions" tabindex="-1">Protocol Buffer Definitions <a class="header-anchor" href="#protocol-buffer-definitions" aria-label="Permalink to &quot;Protocol Buffer Definitions&quot;">​</a></h3><div class="language-protobuf"><button title="Copy Code" class="copy"></button><span class="lang">protobuf</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#B8A6FF;">syntax</span><span style="color:#767676;"> =</span><span style="color:#BFF3C2;"> &quot;proto3&quot;</span><span style="color:#767676;">;</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#B8A6FF;">package</span><span style="color:#BFF3C2;"> evnode.store.v1</span><span style="color:#767676;">;</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#B8A6FF;">message</span><span style="color:#94EEFF;"> Block</span><span style="color:#DBD7CA;"> {</span></span>\n<span class="line"><span style="color:#B8A6FF;">  SignedHeader</span><span style="color:#DBD7CA;"> header </span><span style="color:#767676;">=</span><span style="color:#FFECB6;"> 1</span><span style="color:#767676;">;</span></span>\n<span class="line"><span style="color:#B8A6FF;">  Data</span><span style="color:#DBD7CA;"> data </span><span style="color:#767676;">=</span><span style="color:#FFECB6;"> 2</span><span style="color:#767676;">;</span></span>\n<span class="line"><span style="color:#B8A6FF;">  bytes</span><span style="color:#DBD7CA;"> signature </span><span style="color:#767676;">=</span><span style="color:#FFECB6;"> 3</span><span style="color:#767676;">;</span></span>\n<span class="line"><span style="color:#DBD7CA;">}</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#B8A6FF;">message</span><span style="color:#94EEFF;"> GetBlockRequest</span><span style="color:#DBD7CA;"> {</span></span>\n<span class="line"><span style="color:#B8A6FF;">  oneof</span><span style="color:#DBD7CA;"> identifier {</span></span>\n<span class="line"><span style="color:#B8A6FF;">    uint64</span><span style="color:#DBD7CA;"> height </span><span style="color:#767676;">=</span><span style="color:#FFECB6;"> 1</span><span style="color:#767676;">;</span></span>\n<span class="line"><span style="color:#B8A6FF;">    bytes</span><span style="color:#DBD7CA;"> hash </span><span style="color:#767676;">=</span><span style="color:#FFECB6;"> 2</span><span style="color:#767676;">;</span></span>\n<span class="line"><span style="color:#DBD7CA;">  }</span></span>\n<span class="line"><span style="color:#DBD7CA;">}</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#B8A6FF;">message</span><span style="color:#94EEFF;"> GetBlockResponse</span><span style="color:#DBD7CA;"> {</span></span>\n<span class="line"><span style="color:#B8A6FF;">  Block</span><span style="color:#DBD7CA;"> block </span><span style="color:#767676;">=</span><span style="color:#FFECB6;"> 1</span><span style="color:#767676;">;</span></span>\n<span class="line"><span style="color:#DBD7CA;">}</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#B8A6FF;">message</span><span style="color:#94EEFF;"> GetStateResponse</span><span style="color:#DBD7CA;"> {</span></span>\n<span class="line"><span style="color:#B8A6FF;">  State</span><span style="color:#DBD7CA;"> state </span><span style="color:#767676;">=</span><span style="color:#FFECB6;"> 1</span><span style="color:#767676;">;</span></span>\n<span class="line"><span style="color:#DBD7CA;">}</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#B8A6FF;">service</span><span style="color:#94EEFF;"> StoreService</span><span style="color:#DBD7CA;"> {</span></span>\n<span class="line"><span style="color:#A0A0A0;">  // Query Methods</span></span>\n<span class="line"><span style="color:#B8A6FF;">  rpc</span><span style="color:#94EEFF;"> GetBlock</span><span style="color:#DBD7CA;">(</span><span style="color:#94EEFF;">GetBlockRequest</span><span style="color:#DBD7CA;">) </span><span style="color:#B8A6FF;">returns</span><span style="color:#DBD7CA;"> (</span><span style="color:#94EEFF;">GetBlockResponse</span><span style="color:#DBD7CA;">) {}</span></span>\n<span class="line"><span style="color:#B8A6FF;">  rpc</span><span style="color:#94EEFF;"> GetState</span><span style="color:#DBD7CA;">(</span><span style="color:#94EEFF;">google</span><span style="color:#DBD7CA;">.</span><span style="color:#94EEFF;">protobuf</span><span style="color:#DBD7CA;">.</span><span style="color:#94EEFF;">Empty</span><span style="color:#DBD7CA;">) </span><span style="color:#B8A6FF;">returns</span><span style="color:#DBD7CA;"> (</span><span style="color:#94EEFF;">GetStateResponse</span><span style="color:#DBD7CA;">) {}</span></span>\n<span class="line"><span style="color:#DBD7CA;">}</span></span></code></pre></div><h3 id="implementation-structure" tabindex="-1">Implementation Structure <a class="header-anchor" href="#implementation-structure" aria-label="Permalink to &quot;Implementation Structure&quot;">​</a></h3><div class="language-txt"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span>pkg/</span></span>\n<span class="line"><span>    rpc/</span></span>\n<span class="line"><span>      server/</span></span>\n<span class="line"><span>        server.go         // Connect-RPC server implementation</span></span>\n<span class="line"><span>      client/</span></span>\n<span class="line"><span>        client.go         // Connect-RPC client implementation</span></span></code></pre></div><h2 id="status" tabindex="-1">Status <a class="header-anchor" href="#status" aria-label="Permalink to &quot;Status&quot;">​</a></h2><p>Proposed</p><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><h3 id="positive" tabindex="-1">Positive <a class="header-anchor" href="#positive" aria-label="Permalink to &quot;Positive&quot;">​</a></h3><ul><li>Enables remote access to store data</li><li>Type-safe API interactions</li><li>Protocol flexibility (gRPC and HTTP/1.1)</li><li>Modern developer experience</li><li>Built-in streaming support</li></ul><h3 id="negative" tabindex="-1">Negative <a class="header-anchor" href="#negative" aria-label="Permalink to &quot;Negative&quot;">​</a></h3><ul><li>Additional dependency on Connect-Go</li><li>Need to maintain protocol buffer definitions</li><li>Potential version compatibility challenges</li></ul><h3 id="neutral" tabindex="-1">Neutral <a class="header-anchor" href="#neutral" aria-label="Permalink to &quot;Neutral&quot;">​</a></h3><ul><li>Requires generating and maintaining additional code</li><li>Need for proper API versioning strategy</li></ul><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ul><li><a href="https://connectrpc.com/docs/go/getting-started/" target="_blank" rel="noreferrer">Connect-RPC Documentation</a></li><li><a href="https://protobuf.dev" target="_blank" rel="noreferrer">Protocol Buffers Documentation</a></li><li><a href="./../../pkg/store/types.go">Store Interface Documentation</a></li></ul>',30)])])}]]);export{o as __pageData,l as default};
